    val log = IntArray(n + 1) { 0 }
    for (i in 2..n) {
        log[i] = log[i / 2] + 1
    }
    val LG = if (n==0) 1 else log[n] + 1

    val st = Array(LG) { LongArray(n) }
    for (i in 0 until n) {
        st[0][i] = nums[i]
    }
    for (k in 1 until LG) {
        val step = 1 shl (k - 1)
        for (i in 0 until n - (1 shl k) + 1) {
            st[k][i] = gcd(st[k-1][i], st[k-1][i + step])
