    fun query(l: Int, r: Int): Long {
        val len = r - l + 1
        if (len <= 0) return 0
        val k = log[len]
        return gcd(st[k][l], st[k][r - (1 shl k) + 1])
    }

    var low = 0
    var high = n
    var ans = n.toLong()

    fun check(x: Int): Boolean {
        val L = x + 1
        if (L > n) {
            return true
