                    return false
                }
                i += L
            } else {
                i++
            }
        }
        return count <= maxC
    }

    while (low <= high) {
        val mid = (low + high) / 2
        if (check(mid)) {
            ans = mid.toLong()
            high = mid - 1
        } else {
            low = mid + 1
        }
    }
    return ans
}
